func seedParticipantsStore(t *testing.T, home string) {
	t.Helper()
	db, err := store.Open(filepath.Join(home, ".local", "share", "superhuman-pp-cli", "data.db"))
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	defer db.Close()
	now := time.Now().UnixMilli()
	if _, err := db.UpsertGmailMessages(t.Context(), []store.StoredMessage{
		{ID: "m1", ThreadID: "t1", AccountEmail: "user@example.com", From: "user@example.com", To: "alice@example.com", Subject: "A", InternalDate: now},
		{ID: "m2", ThreadID: "t2", AccountEmail: "user@example.com", From: "bob@example.com", To: "user@example.com", Subject: "B", InternalDate: now + 1},
	}); err != nil {
		t.Fatalf("upsert: %v", err)
	}
}

func TestParticipantsList(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)
	seedParticipantsStore(t, home)
	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")

	stdout, _, err := executeCmd(t, "--config", configPath, "--json", "participants", "list", "--since", "1d", "--sort", "email")
	if err != nil {
		t.Fatalf("participants list: %v", err)
	}
	var participants []map[string]any
	if err := json.Unmarshal([]byte(stdout), &participants); err != nil {
		t.Fatalf("decode participants: %v\n%s", err, stdout)
	}
	if len(participants) != 2 || participants[0]["email"] != "alice@example.com" {
		t.Fatalf("participants = %+v", participants)
	}
}

